   767→void DAGTypeLegalizer::GetExpandedInteger(SDValue Op, SDValue &Lo,
   768→                                          SDValue &Hi) {
   769→  std::pair<TableId, TableId> &Entry = ExpandedIntegers[getTableId(Op)];
   770→  assert((Entry.first != 0) && "Operand isn't expanded");
