   971→  for (unsigned i = 0, e = N->getNumValues(); i != e; ++i)
   972→    if (i != ResNo)
   973→      ReplaceValueWith(SDValue(N, i), SDValue(N->getOperand(i)));
   974→  return SDValue(N->getOperand(ResNo));
   975→}
